import React, { useEffect, useState } from 'react';
import toast from 'react-hot-toast';
import { getBooksAPI, createBookAPI, updateBookAPI, deleteBookAPI } from '../../api';

const CATEGORIES = ['Fiction','Non-Fiction','Science','Technology','History','Biography','Children','Literature','Philosophy','Other'];
const defaultForm = { title:'', author:'', isbn:'', category:'Other', totalCopies:1, publisher:'', publishedYear:'', description:'' };

export default function BooksPage() {
  const [books, setBooks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [category, setCategory] = useState('All');
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState(defaultForm);
  const [saving, setSaving] = useState(false);

  useEffect(() => { load(); }, [search, category]);

  const load = async () => {
    try { setLoading(true); const r = await getBooksAPI({ search, category }); setBooks(r.data.data); }
    catch { toast.error('Failed to load books'); }
    finally { setLoading(false); }
  };

  const openAdd = () => { setEditing(null); setForm(defaultForm); setShowModal(true); };
  const openEdit = (b) => { setEditing(b); setForm({ ...b, publishedYear: b.publishedYear || '' }); setShowModal(true); };
  const close = () => { setShowModal(false); setEditing(null); setForm(defaultForm); };
  const hc = (e) => setForm(p => ({ ...p, [e.target.name]: e.target.value }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      setSaving(true);
      if (editing) { await updateBookAPI(editing._id, form); toast.success('Book updated!'); }
      else { await createBookAPI(form); toast.success('Book added!'); }
      close(); load();
    } catch (err) { toast.error(err.response?.data?.message || 'Error'); }
    finally { setSaving(false); }
  };

  const handleDelete = async (b) => {
    if (!window.confirm(`Delete "${b.title}"?`)) return;
    try { await deleteBookAPI(b._id); toast.success('Book deleted!'); load(); }
    catch (err) { toast.error(err.response?.data?.message || 'Cannot delete'); }
  };

  return (
    <div className="page-enter">
      <div className="ap-header">
        <h1 className="ap-title">📚 Books</h1>
        <button className="ap-btn ap-btn--gold" onClick={openAdd}>+ Add Book</button>
      </div>

      <div className="ap-table-box">
        <div className="ap-table-top">
          <input className="ap-search" placeholder="Search title, author, ISBN..." value={search} onChange={e => setSearch(e.target.value)} />
          <select className="ap-search" style={{ width: 160 }} value={category} onChange={e => setCategory(e.target.value)}>
            <option value="All">All Categories</option>
            {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
          <span className="ap-count">{books.length} books</span>
        </div>

        {loading ? <div className="ap-loading"><div className="spinner" /></div>
          : books.length === 0 ? <div className="ap-empty"><div className="ap-empty-icon">📚</div><p>No books found</p></div>
          : (
            <table className="ap-table">
              <thead><tr><th>Title & Author</th><th>ISBN</th><th>Category</th><th>Total</th><th>Available</th><th>Actions</th></tr></thead>
              <tbody>
                {books.map(b => (
                  <tr key={b._id}>
                    <td><strong>{b.title}</strong><br /><span style={{ fontSize:11, color:'var(--text3)' }}>by {b.author}</span></td>
                    <td style={{ fontFamily:'monospace', fontSize:12 }}>{b.isbn}</td>
                    <td><span className="ap-badge ap-badge--blue">{b.category}</span></td>
                    <td>{b.totalCopies}</td>
                    <td><span className={`ap-badge ${b.availableCopies > 0 ? 'ap-badge--green' : 'ap-badge--red'}`}>{b.availableCopies}</span></td>
                    <td>
                      <div className="ap-actions">
                        <button className="ap-btn ap-btn--ghost ap-btn--sm" onClick={() => openEdit(b)}>✏️ Edit</button>
                        <button className="ap-btn ap-btn--danger ap-btn--sm" onClick={() => handleDelete(b)}>🗑️</button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
      </div>

      {showModal && (
        <div className="ap-modal-overlay" onClick={close}>
          <div className="ap-modal" onClick={e => e.stopPropagation()}>
            <div className="ap-modal-title">{editing ? 'Edit Book' : 'Add New Book'}</div>
            <form onSubmit={handleSubmit} className="ap-form">
              <div className="ap-form-grid">
                <div className="ap-form-group ap-form-full">
                  <label className="ap-form-label">Title *</label>
                  <input className="ap-form-input" name="title" value={form.title} onChange={hc} required placeholder="Book title" />
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">Author *</label>
                  <input className="ap-form-input" name="author" value={form.author} onChange={hc} required placeholder="Author name" />
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">ISBN *</label>
                  <input className="ap-form-input" name="isbn" value={form.isbn} onChange={hc} required placeholder="978-..." />
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">Category</label>
                  <select className="ap-form-input" name="category" value={form.category} onChange={hc}>
                    {CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">Total Copies *</label>
                  <input className="ap-form-input" type="number" name="totalCopies" value={form.totalCopies} onChange={hc} required min="1" />
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">Publisher</label>
                  <input className="ap-form-input" name="publisher" value={form.publisher} onChange={hc} placeholder="Publisher" />
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">Published Year</label>
                  <input className="ap-form-input" type="number" name="publishedYear" value={form.publishedYear} onChange={hc} placeholder="2023" />
                </div>
                <div className="ap-form-group ap-form-full">
                  <label className="ap-form-label">Description</label>
                  <textarea className="ap-form-input" name="description" value={form.description} onChange={hc} rows="3" placeholder="Brief description..." style={{ resize:'vertical' }} />
                </div>
              </div>
              <div className="ap-form-actions">
                <button type="button" className="ap-btn ap-btn--ghost" onClick={close}>Cancel</button>
                <button type="submit" className="ap-btn ap-btn--gold" disabled={saving}>{saving ? 'Saving...' : editing ? 'Update' : 'Add Book'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
